#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct LedgerEntry {
    pub sequence_id: u64,
    pub timestamp: String,
    pub event_type: String,
    pub actor: String,
    pub object_ref: String,
    pub detail_hash: String,
    pub previous_hash: String,
